class Deployer:
    def __init__(self, log_path: str = '/var/log/deploy.log'):
        self.log_path = log_path
        try:
            logging.basicConfig(filename=self.log_path, level=logging.INFO)
        except PermissionError:
            fallback = os.path.join(os.getcwd(), 'deploy.log')
            logging.basicConfig(filename=fallback, level=logging.INFO)
            self.log_path = fallback
        self.logger = logging.getLogger('deployer')
